using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class PlayerController : MonoBehaviour
{
    public float turnSpeed = 10f;
    public float moveSpeed = 5f;

    private Rigidbody rb;

    // Start is called before the first frame update
    void Start()
    {
        rb = GetComponent<Rigidbody>();
    }

    // Update is called once per frame
    void FixedUpdate()
    {
        float horizontalInput = Input.GetAxis("Horizontal");
        float verticalInput = Input.GetAxis("Vertical");

        // Turning
        float turn = horizontalInput * turnSpeed * Time.deltaTime;
        Quaternion turnRotation = Quaternion.Euler(0, turn, 0);
        transform.rotation = transform.rotation * turnRotation;

        // Moving
        Vector3 movement = transform.forward * verticalInput * moveSpeed * Time.deltaTime;
        rb.MovePosition(transform.position + movement);
    }
}
```

In this script, the `FixedUpdate` method is used instead of `Update` because it's generally better for physics-related code. The `Input.GetAxis` method is used to get the horizontal and vertical input from the player

Here's an example of how you can modify a language model to compute the perplexity of a test set. We'll use a simple language model that uses a dictionary to store the probabilities of words in the training data.

```python
import math
import random

class LanguageModel:
    def __init__(self):
        self.word_counts = {}
        self.total_words = 0

    def train(self, data):
        for sentence in data:
            for word in sentence.split():
                if word not in self.word_counts:
                    self.word_counts[word] = 1
                else:
                    self.word_counts[word] += 1
                self.total_words += 1

    def calculate_probability(self, word):
        if word not in self.word_counts:
            return 0
        return self.word_counts[word] / self.total_words

    def perplexity(self, test_data):
        perplexity = 1
        for sentence in test_data:
            sentence_probability = 1
            for word in sentence.split():
                sentence_probability *= self.calculate_probability(word)
            perplexity *= (1 / sentence_probability)
        return math.pow(perplexity, 1 / len(test_data))

